// 1. Array parsing setup
const lines = compressedData.split("\n");
const questionsDB = [];

const catMap = {
    'H': 'History',
    'G': 'Geography',
    'S': 'Science',
    'A': 'Academics'
};

// 2. Inflate the questions
for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    
    const parts = line.split('|');
    if (parts.length < 7) continue;

    const cat = catMap[parts[0]];
    const ans = parts[1].split(',');
    
    // Unpack clues
    const c_varsity = parts[2];
    const c_jv = parts[3];
    const c_mid = parts[4];
    const c_elem = parts[5];
    const c_common = parts[6];

    // Varsity uses Varsity, JV, and Common clues
    questionsDB.push({
        level: "Varsity",
        topic: cat,
        text: c_varsity + " (*) " + c_jv + " (+) For 10 points, " + c_common,
        answers: ans
    });

    // JV uses JV, Middle, and Common clues
    questionsDB.push({
        level: "JV",
        topic: cat,
        text: c_jv + " (*) " + c_mid + " (+) For 10 points, " + c_common,
        answers: ans
    });

    // Middle uses Middle, Elementary, and Common clues
    questionsDB.push({
        level: "Middle",
        topic: cat,
        text: c_mid + " (*) " + c_elem + " (+) For 10 points, " + c_common,
        answers: ans
    });

    // Elementary uses just the Elementary and Common clues
    questionsDB.push({
        level: "Elementary",
        topic: cat,
        text: c_elem + " (*) For 10 points, " + c_common,
        answers: ans
    });
}

// 3. Optional shuffle so questions don't always appear in exact order:
for (let i = questionsDB.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [questionsDB[i], questionsDB[j]] = [questionsDB[j], questionsDB[i]];
}

// Export via window object
window.questionsDB = questionsDB;
